// Calculate MRR from active subscriptions
const subscriptions = $input.all();

let mrr = 0;
let activeCustomers = new Set();
let topAccounts = [];
let planBreakdown = {};

subscriptions.forEach(sub => {
  const status = sub.json.status;
  if (status !== 'active' && status !== 'trialing') return;

  const customerId = sub.json.customer;
  activeCustomers.add(customerId);

  // Sum line items, normalize to monthly
  let subMrr = 0;
  const items = sub.json.items?.data || [];
  items.forEach(item => {
    const unitAmount = (item.price?.unit_amount || 0) / 100; // cents to dollars
    const interval = item.price?.recurring?.interval || 'month';
    const intervalCount = item.price?.recurring?.interval_count || 1;
    const quantity = item.quantity || 1;

    // Normalize to monthly
    let monthlyAmount = unitAmount * quantity;
    if (interval === 'year') monthlyAmount = monthlyAmount / 12;
    if (interval === 'week') monthlyAmount = monthlyAmount * 4.33;
    monthlyAmount = monthlyAmount / intervalCount;

    subMrr += monthlyAmount;

    // Track plan breakdown
    const planName = item.price?.nickname || item.price?.id || 'Unknown';
    planBreakdown[planName] = (planBreakdown[planName] || 0) + monthlyAmount;
  });

  mrr += subMrr;
  topAccounts.push({
    customer: customerId,
    customerName: sub.json.customer_name || customerId,
    mrr: subMrr
  });
});

// Sort top accounts by MRR
topAccounts.sort((a, b) => b.mrr - a.mrr);
const top5 = topAccounts.slice(0, 5);

return {
  mrr: Math.round(mrr * 100) / 100,
  activeCustomerCount: activeCustomers.size,
  topAccounts: top5,
  planBreakdown
};

// Calculate churn from invoices (last 30 days vs previous 30 days)
const invoices = $input.all();
const now = Math.floor(Date.now() / 1000);
const thirtyDaysAgo = now - 30 * 86400;
const sixtyDaysAgo = now - 60 * 86400;

let newCustomers = new Set();
let churnedCustomers = new Set();
let totalRevenueThisPeriod = 0;

invoices.forEach(inv => {
  const created = inv.json.created;
  const customerId = inv.json.customer;
  const amount = (inv.json.total || 0) / 100;
  const status = inv.json.status;

  if (status !== 'paid') return;

  // Check if this customer's first invoice is in this period
  if (created >= thirtyDaysAgo) {
    totalRevenueThisPeriod += amount > 0 ? amount : 0;
  }

  // Simple churn detection: look for canceled subscription metadata
  // In practice, you'd cross-reference with subscription status changes
  if (inv.json.metadata?.canceled === 'true' || inv.json.billing_reason === 'subscription_cycle' && amount === 0) {
    if (created >= thirtyDaysAgo) {
      churnedCustomers.add(customerId);
    }
  }
});

// For demo: estimate new customers as those with invoices only in this period
// In production: query Stripe for subscriptions created in last 30 days

return {
  churnedCount: churnedCustomers.size,
  churnRate: 0, // Calculated in merge step with MRR data
  revenueThisPeriod: Math.round(totalRevenueThisPeriod * 100) / 100
};

// Combine MRR and churn data, calculate derived metrics
const mrrData = $('Calculate MRR').first().json;
const churnData = $input.first().json;

const activeCustomers = mrrData.activeCustomerCount;
const mrr = mrrData.mrr;

// Calculate churn more accurately if we have the data
const churnedCount = churnData.churnedCount;
const churnRate = activeCustomers > 0 ? (churnedCount / (activeCustomers + churnedCount)) * 100 : 0;

const arpu = activeCustomers > 0 ? mrr / activeCustomers : 0;
const ltv = churnRate > 0 ? arpu / (churnRate / 100) : 0;

const today = new Date().toISOString().split('T')[0];

return {
  date: today,
  mrr: Math.round(mrr * 100) / 100,
  activeCustomers,
  churnedCount,
  churnRate: Math.round(churnRate * 100) / 100,
  arpu: Math.round(arpu * 100) / 100,
  ltv: Math.round(ltv * 100) / 100,
  topAccounts: mrrData.topAccounts,
  planBreakdown: mrrData.planBreakdown
};

// Format the metrics into a row for Google Sheets
const data = $input.first().json;

return {
  sheetRow: [
    data.date,
    data.mrr,
    data.activeCustomers,
    data.churnedCount,
    data.churnRate,
    data.arpu,
    data.ltv,
    data.topAccounts[0]?.customerName || '—',
    data.topAccounts[1]?.customerName || '—',
    data.topAccounts[2]?.customerName || '—'
  ]
};

// Read previous week for comparison
const currentData = $('Calculate LTV & ARPU').first().json;

// For delta calculation: read the previous row from Google Sheets
// In production: use a Google Sheets Read node to get last week's data
const dashboardData = $input.first().json;

// Simplified delta — in production, compare against previous row
const mrrTrend = '→'; // Placeholder: calculate actual delta
const customerTrend = '→';
const churnTrend = '→';

return {
  current: currentData,
  trends: {
    mrr: mrrTrend,
    customers: customerTrend,
    churn: churnTrend
  }
};

